// خدمة Google OAuth الحقيقية
// تحصل على بيانات المستخدم الفعلية من Google

export const getGoogleUserInfo = async (code: string) => {
  try {
    // إرسال الكود للـ Backend لاستبداله بـ token والحصول على بيانات المستخدم
    const response = await fetch('http://localhost:5000/api/auth/google', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ code }),
    });

    if (!response.ok) {
      throw new Error('Failed to get Google user info');
    }

    const data = await response.json();
    return data.user;
  } catch (error) {
    console.error('Google Auth Error:', error);
    throw error;
  }
};

// دالة بديلة للـ Frontend فقط (بدون Backend)
// هذه تستخدم Google People API مباشرة
export const getGoogleUserInfoFrontend = async (code: string) => {
  try {
    // استبدال الكود بـ access token
    const tokenResponse = await fetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        code,
        client_id: '866642345311-4kiub26p4228g5q7edh3svh05vmn19gn.apps.googleusercontent.com',
        client_secret: 'YOUR_CLIENT_SECRET_HERE', // تحتاج لهذا في Backend فقط
        redirect_uri: 'http://localhost:3000/auth/google/callback',
        grant_type: 'authorization_code',
      }),
    });

    const tokenData = await tokenResponse.json();

    // الحصول على معلومات المستخدم
    const userResponse = await fetch('https://www.googleapis.com/oauth2/v2/userinfo', {
      headers: {
        Authorization: `Bearer ${tokenData.access_token}`,
      },
    });

    const userData = await userResponse.json();

    return {
      email: userData.email,
      firstName: userData.given_name,
      lastName: userData.family_name,
      picture: userData.picture,
    };
  } catch (error) {
    console.error('Google Auth Error:', error);
    throw error;
  }
};
